import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import './HospitalLogin.css';

const HospitalLogin = () => {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);
  const navigate = useNavigate();

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError('');
    setLoading(true);
    try {
      const res = await fetch('http://localhost:9000/api/hospital/login', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ email, password })
      });
      const data = await res.json();
      if (res.ok) {
        localStorage.setItem('hospitalToken', data.token);
        localStorage.setItem('hospitalInfo', JSON.stringify(data.hospital));
        navigate('/hospital-dashboard');
      } else {
        setError(data.message || 'Login failed');
      }
    } catch {
      setError('Network error. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="hl-container">
      <div className="hl-card">
        <div className="hl-logo">🏥</div>
        <h2>Hospital Admin Login</h2>
        <p className="hl-subtitle">Sign in to your HealthMandala hospital portal</p>
        <form onSubmit={handleSubmit}>
          <div className="hl-field">
            <label>Email Address</label>
            <input
              type="email"
              value={email}
              onChange={e => setEmail(e.target.value)}
              placeholder="your@hospital.com"
              required
            />
          </div>
          <div className="hl-field">
            <label>Password</label>
            <input
              type="password"
              value={password}
              onChange={e => setPassword(e.target.value)}
              placeholder="Enter your password"
              required
            />
          </div>
          {error && <p className="hl-error">{error}</p>}
          <button type="submit" className="hl-button" disabled={loading}>
            {loading ? 'Signing in...' : 'Sign In'}
          </button>
        </form>
      </div>
    </div>
  );
};

export default HospitalLogin;
